import{_ as a,o as i,c as t,a2 as o}from"./chunks/framework.Bix3-HpO.js";const m=JSON.parse('{"title":"Analytics","description":"Click and Impression Tracking in Nonaki","frontmatter":{"title":"Analytics","description":"Click and Impression Tracking in Nonaki","weight":30,"extra":{"order":30},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/nonaki/analytics"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/nonaki/analytics"}],["meta",{"property":"og:title","content":"Analytics"}],["meta",{"property":"og:description","content":"Click and Impression Tracking in Nonaki"}],["meta",{"name":"twitter:title","content":"Analytics"}],["meta",{"name":"twitter:description","content":"Click and Impression Tracking in Nonaki"}]]},"headers":[],"relativePath":"docs/nonaki/analytics.md","filePath":"docs/nonaki/analytics.md"}'),n={name:"docs/nonaki/analytics.md"};function r(s,e,l,c,d,h){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="analytics" tabindex="-1">Analytics <a class="header-anchor" href="#analytics" aria-label="Permalink to &quot;Analytics&quot;">​</a></h1><p>Nonaki tracks both clicks (when a visitor follows a redirect) and impressions (when a page containing your link is viewed). Open any link&#39;s analytics from the <strong>Links</strong> view to see its performance.</p><hr><h2 id="clicks" tabindex="-1">Clicks <a class="header-anchor" href="#clicks" aria-label="Permalink to &quot;Clicks&quot;">​</a></h2><p>A click is recorded every time a visitor follows one of your redirect links. Nonaki captures:</p><ul><li>Date and time</li><li>Device type, browser, and operating system</li><li>Country (from CDN headers if available, otherwise from <a href="/docs/nonaki/geoip">GeoIP</a> if configured)</li><li>Referrer URL</li><li>Whether the visitor was identified as a bot</li></ul><p>Clicks are processed asynchronously — recorded to a queue first, then enriched and moved to the analytics tables by a background job that runs every 5 minutes. This helps keep the redirects fast while being able to track click activities.</p><hr><h2 id="impressions" tabindex="-1">Impressions <a class="header-anchor" href="#impressions" aria-label="Permalink to &quot;Impressions&quot;">​</a></h2><p>An impression is recorded when a page on your site that contains one of your links is loaded. The tracking is handled by a lightweight beacon that fires in the background and does not affect page load time.</p><p>Impressions capture:</p><ul><li>Date and time</li><li>Device type, browser, and operating system</li><li>Country (from CDN headers if available, otherwise from <a href="/docs/nonaki/geoip">GeoIP</a> if configured)</li><li>The page URL where the link appeared</li></ul><p>To avoid inflating counts, a maximum of one impression per visitor per link per page is recorded within any 60-second window.</p><hr><h2 id="bot-detection" tabindex="-1">Bot Detection <a class="header-anchor" href="#bot-detection" aria-label="Permalink to &quot;Bot Detection&quot;">​</a></h2><p>Both clicks and impressions are checked for bot traffic. Nonaki uses device/user-agent analysis combined with a list of known datacenter and ASN IP ranges. Bot events are stored but excluded from the default analytics view so your numbers reflect real visitors.</p><hr><h2 id="analytics-view" tabindex="-1">Analytics View <a class="header-anchor" href="#analytics-view" aria-label="Permalink to &quot;Analytics View&quot;">​</a></h2><p>Click the chart icon on any link row to open its analytics. The view includes:</p><h3 id="chart" tabindex="-1">Chart <a class="header-anchor" href="#chart" aria-label="Permalink to &quot;Chart&quot;">​</a></h3><p>A dual-axis chart showing daily clicks and impressions over the selected time range. Bots are excluded by default.</p><h3 id="stat-cards" tabindex="-1">Stat Cards <a class="header-anchor" href="#stat-cards" aria-label="Permalink to &quot;Stat Cards&quot;">​</a></h3><p>Four summary cards at a glance:</p><ul><li><strong>Total Clicks</strong></li><li><strong>Total Impressions</strong></li><li><strong>CTR</strong> — click-through rate (clicks ÷ impressions)</li><li><strong>Avg Clicks / Day</strong></li></ul><h3 id="breakdowns" tabindex="-1">Breakdowns <a class="header-anchor" href="#breakdowns" aria-label="Permalink to &quot;Breakdowns&quot;">​</a></h3><p>Detailed tables showing the distribution of traffic by:</p><ul><li><strong>Device</strong> — Desktop, Mobile, Tablet</li><li><strong>Browser</strong> — Chrome, Firefox, Safari, etc.</li><li><strong>Operating System</strong> - MacOS, Linux, Windows, iOS, Android, etc.</li><li><strong>Country</strong> — requires GeoIP to be configured</li><li><strong>Referrer</strong> — top referring domains</li><li><strong>Top Pages</strong> — pages on your site where the link appeared (impressions only)</li></ul><h3 id="time-range" tabindex="-1">Time Range <a class="header-anchor" href="#time-range" aria-label="Permalink to &quot;Time Range&quot;">​</a></h3><p>Use the selector in the top-right to change the time window: <code>7 days</code>, <code>30 days</code>, <code>90 days</code>, <code>1 year</code>, or <code>All time</code>.</p>',29)])])}const k=a(n,[["render",r]]);export{m as __pageData,k as default};
